public final class Stage2FactorAcceptanceTest{public static void main(String[]a){LocalDate as=LocalDate.of(2026,7,20);Clock clock=Clock.fixed(Instant.parse("2026-07-20T04:00:00Z"),ZoneId.of("Asia/Shanghai"));MarketDataProvider market=new MarketDataProvider(){public com.stockmind.domain.market.MarketQuote loadQuote(String id){int x=Math.abs(id.hashCode()%5);return new com.stockmind.domain.market.MarketQuote(id,"q","fixture",Instant.parse("2026-07-20T03:00:00Z"),id.endsWith("600519")?"贵州茅台":"同行",BigDecimal.valueOf(100+x),BigDecimal.valueOf(99),BigDecimal.valueOf(99),BigDecimal.valueOf(101),BigDecimal.valueOf(98),BigDecimal.ONE,BigDecimal.ONE,BigDecimal.valueOf(1000),BigDecimal.valueOf(1000),BigDecimal.ONE,BigDecimal.valueOf(18+x),BigDecimal.valueOf(4+x),BigDecimal.valueOf(1000),BigDecimal.valueOf(900),BigDecimal.valueOf(110),BigDecimal.valueOf(90),BigDecimal.ONE,List.of());}public BarDataset loadBars(HistoricalBarsQuery q){List<MarketBar>b=new ArrayList<>();LocalDate d=q.endDate().minusYears(6);int i=0;while(!d.isAfter(q.endDate())){if(d.getDayOfWeek()!=DayOfWeek.SATURDAY&&d.getDayOfWeek()!=DayOfWeek.SUNDAY){Instant t=d.atTime(15,0).atZone(ZoneId.of("Asia/Shanghai")).toInstant();BigDecimal p=BigDecimal.valueOf(50+i*.03);b.add(new MarketBar(q.instrumentId(),BarInterval.DAY_1,t.minusSeconds(19800),t,p,p,p,p,BigDecimal.valueOf(1000),BigDecimal.valueOf(100000),q.adjustment()));i++;}d=d.plusDays(1);}return new BarDataset("b",b,"fixture",Instant.parse("2026-07-20T08:00:00Z"),List.of());}};FinancialReportProvider financial=(symbol,type,periods)->statements(type);AnalystResearchProvider research=(symbol,limit)->reports();DividendProvider dividends=(symbol,limit)->List.of(new DividendDistribution(as.minusMonths(2),BigDecimal.TEN,"实施"));SectorDataProvider sector=new SectorDataProvider(){public List<SectorSnapshot>loadIndustrySectors(String s){return List.of();}public SectorConstituentSet loadTopIndustryConstituents(String s,int l){List<SectorConstituent>c=new ArrayList<>();c.add(new SectorConstituent("SH600519","贵州茅台",BigDecimal.TEN));for(int i=0;i<8;i++)c.add(new SectorConstituent("SH6000"+(10+i),"同行"+i,BigDecimal.TEN));return new SectorConstituentSet("BK","白酒",c);}};SupplementalRiskProvider risk=(symbol,date)->new SupplementalRiskSnapshot(date,true,new BigDecimal("0.02"),new BigDecimal("0.08"),new BigDecimal("0.25"),new BigDecimal("0.12"),new BigDecimal("-0.08"),List.of("fixture_risk"),List.of());var service=new PointInTimeStockSnapshotService(new InstrumentResolver(),market,financial,research,dividends,sector,risk,clock);var s=service.load("SH600519",as);var valuation=new ValuationFactorCalculator().calculate(s);require(factor(valuation,"pe_ttm_percentile_5y").quality()==FactorQuality.VALID,"5年PE历史分位样本不足或未按时点重建");var quality=new QualityFactorCalculator().calculate(s);require(factor(quality,"free_cash_flow_cny").quality()==FactorQuality.VALID&&factor(quality,"roe_pct").quality()==FactorQuality.VALID,"FCF/ROE深度质量因子缺失");var expectation=new ExpectationRevisionFactorCalculator().calculate(s);require(factor(expectation,"eps_revision_180d_pct").quality()==FactorQuality.VALID,"180天EPS修正缺失");var momentum=new MomentumRiskFactorCalculator().calculate(s);require(momentum.warnings().contains(FactorWarning.UPCOMING_LOCKUP_RELEASE)&&momentum.warnings().contains(FactorWarning.MARGIN_CROWDING_RISING),"补充风险标记缺失");var sensitivityOnly=new ScenarioValuationService(service).analyze("SH600519",as,Map.of());require(!sensitivityOnly.uniqueRangeAvailable()&&sensitivityOnly.scenarios().isEmpty()&&sensitivityOnly.sensitivityMatrix().size()==9,"未提供Forward PE假设时必须只返回敏感性矩阵");require(!sensitivityOnly.ttmPeComparableToTargetPe()&&"NEXT_FISCAL_YEAR_INSTITUTION_CONSENSUS_MEDIAN".equals(sensitivityOnly.scenarioEpsBasis()),"TTM与Forward估值口径未分离");var scenario=new ScenarioValuationService(service).analyze("SH600519",as,Map.of("PESSIMISTIC",BigDecimal.valueOf(15),"BASE",BigDecimal.valueOf(20),"OPTIMISTIC",BigDecimal.valueOf(25)));require(scenario.uniqueRangeAvailable()&&scenario.scenarios().size()==3&&"USER_INPUT_FORWARD_PE".equals(scenario.targetPeSource()),"完整用户Forward PE假设未生成情景");}
 private static FactorValue factor(FactorCategoryResult r,String n){return r.factors().stream().filter(x->x.name().equals(n)).findFirst().orElseThrow();}private static List<FinancialStatementPeriod>statements(String type){List<FinancialStatementPeriod>r=new ArrayList<>();for(int y=2020;y<=2025;y++){LocalDate rp=LocalDate.of(y,12,31),pub=LocalDate.of(y+1,4,20);Map<String,String>v=switch(type){case"lrb"->Map.of("基本每股收益",String.valueOf(5+y-2020),"营业收入","1000","净利润","300","扣非净利润","280","营业利润","350","所得税费用","50","利润总额","400");case"fzb"->Map.of("每股净资产",String.valueOf(20+y-2020),"资产总计","3000","负债合计","900","所有者权益合计","2100","货币资金","500","短期借款","200","商誉","100","应收账款","200","存货","300");default->Map.of("经营活动产生的现金流量净额","400","购建固定资产、无形资产和其他长期资产支付的现金","100");};Map<String,String>yoy=Map.of("营业收入","0.10","净利润","0.12","应收账款","0.08","存货","0.09");r.add(new FinancialStatementPeriod(rp,pub,type,v,yoy));}return r;}private static List<AnalystReport>reports(){List<AnalystReport>r=new ArrayList<>();for(int i=0;i<3;i++){r.add(new AnalystReport("new"+i,"600519","新","机构"+i,LocalDate.of(2026,7,1),"买入",BigDecimal.valueOf(10+i*.1),BigDecimal.valueOf(11+i*.1),BigDecimal.valueOf(12+i*.1),""));r.add(new AnalystReport("old"+i,"600519","旧","机构"+i,LocalDate.of(2025,12,1),"买入",BigDecimal.valueOf(9+i*.1),BigDecimal.TEN,BigDecimal.valueOf(11),""));}return r;}private static void require(boolean c,String m){if(!c)throw new AssertionError(m);}}
